def matrixChainOrder(p: list[int]) -> int:
    n = len(p)
    if n <= 1:
        return 0

    dp = [0] * n

    for l in range(2, n):
        for i in range(n - l):
            j = i + l
            dp[j] = float('inf')
            for k in range(i, j):
                q = dp[i] + dp[k] + p[i] * p[k+1] * p[j]
                if q < dp[j]:
                    dp[j] = q

    return dp[n-1]

