import heapq

def dijkstra(adj, s):
    n = len(adj)
    dist = [float('inf')] * n
    dist[s] = 0
    pq = [(0, s)]

    while pq:
        current_dist, u = heapq.heappop(pq)

        if current_dist > dist[u]:
            continue

        for v, w in adj[u]:
            distance = current_dist + w

            if distance < dist[v]:
                dist[v] = distance
                heapq.heappush(pq, (distance, v))

    return dist

