def adjList(n, edges):
    adj = [[] for _ in range(n)]
    for u, v in edges:
        if v not in adj[u]:
            adj[u].append(v)
        if u not in adj[v]:
            adj[v].append(u)
    for i in range(n):
        adj[i].sort()
